Headphone Check:
🎧 Please listen to the following audio clip and indicate whether the sound is played from the
 left channel, right channel, or both channels.





    Dein Browser unterstützt das Audio-Element nicht.



Qualtrics.SurveyEngine.addOnload(function () {

    var audio = document.getElementById("stimulusAudio2");
    if (!audio) return;

    // Force full volume initially
    audio.volume = 1;
    audio.muted = false;

    // Prevent participant from changing volume
    audio.addEventListener("volumechange", function () {
        setTimeout(function () {
            audio.volume = 1;
            audio.muted = false;
        }, 0);
    });

    // Ensure consistent playback behavior
    audio.addEventListener("play", function () {
        audio.volume = 1;
        audio.muted = false;
    });

});
